+            self.blinkAmounts[provider] = 0
+            self.tiltAmounts[provider] = 0
+        case .tilt:
+            self.tiltAmounts[provider] = amount
+            self.blinkAmounts[provider] = 0
+            self.wiggleAmounts[provider] = 0
+        }
+    }
